using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------

/// <summary>Tools the research agent can invoke during its loop.</summary>
static class ResearchTools
{
    private static readonly HttpClient s_http = new();
    private static readonly List<string> s_notes = [];

    [Description("Search the web for a query and return a summary of the top results. Use this to discover facts about a topic.")]
    public static async Task<string> WebSearch(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍  Searching: {query}");

        // Use Wikipedia's public search API (no key required).
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://en.wikipedia.org/w/api.php?action=opensearch&search={encoded}&limit=5&format=json";

        try
        {
            var json = await s_http.GetStringAsync(url);
            // OpenSearch returns: [ query, [titles], [descriptions], [urls] ]
            var doc = System.Text.Json.JsonDocument.Parse(json);
            var titles = doc.RootElement[1];
            var descriptions = doc.RootElement[2];
            var urls = doc.RootElement[3];

            if (titles.GetArrayLength() == 0)
                return "No results found.";

            var sb = new System.Text.StringBuilder();
            for (int i = 0; i < titles.GetArrayLength(); i++)
            {
                sb.AppendLine($"- **{titles[i].GetString()}**: {descriptions[i].GetString()}");
                sb.AppendLine($"  {urls[i].GetString()}");
            }
            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note. Use this to record important facts or findings you want to include in the final summary.")]
    public static string SaveNote(
        [Description("The note text to save")] string note)
    {
        s_notes.Add(note);
        Console.WriteLine($"  📝  Note saved ({s_notes.Count} total)");
        return $"Note saved. You now have {s_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes so far.")]
    public static string GetNotes()
    {
        if (s_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new System.Text.StringBuilder();
        for (int i = 0; i < s_notes.Count; i++)
            sb.AppendLine($"{i + 1}. {s_notes[i]}");
        return sb.ToString();
    }
}

// ---------------------------------------------------------------------------
// Agent loop
// ---------------------------------------------------------------------------

Console.WriteLine("═══════════════════════════════════════");
Console.WriteLine("        🔬  Research Agent  🔬");
Console.WriteLine("═══════════════════════════════════════");

// Resolve the model configuration from environment variables.
var endpoint = Environment.GetEnvironmentVariable("OPENAI_BASE_URL");
var apiKey   = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "unused";
var model    = Environment.GetEnvironmentVariable("OPENAI_MODEL")   ?? "gpt-4o-mini";

var clientOptions = new OpenAIClientOptions();
if (!string.IsNullOrEmpty(endpoint))
    clientOptions.Endpoint = new Uri(endpoint);

IChatClient chatClient = new OpenAI.Chat.ChatClient(model, new System.ClientModel.ApiKeyCredential(apiKey), clientOptions)
    .AsChatClient()
    .AsBuilder()
    .UseFunctionInvocation()          // automatically calls tools
    .Build();

var chatOptions = new ChatOptions
{
    Tools = [
        AIFunctionFactory.Create(ResearchTools.WebSearch),
        AIFunctionFactory.Create(ResearchTools.SaveNote),
        AIFunctionFactory.Create(ResearchTools.GetNotes),
    ],
};

var systemPrompt = """
    You are a research agent. Your job is to research a topic the user gives you.

    Workflow:
    1. Break the topic into 2-3 sub-questions.
    2. Use the WebSearch tool to find information for each sub-question.
    3. Use SaveNote to record the most important facts you discover.
    4. After gathering enough information, use GetNotes to review your notes.
    5. Provide a well-structured summary with sections and key takeaways.

    Always cite the sources (URLs) you found during search.
    """;

List<ChatMessage> messages =
[
    new(ChatRole.System, systemPrompt),
];

Console.WriteLine();
Console.Write("Enter a research topic (or 'quit' to exit): ");
var topic = Console.ReadLine();

while (!string.IsNullOrWhiteSpace(topic) && !topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
{
    messages.Add(new(ChatRole.User, $"Research the following topic and provide a summary: {topic}"));

    Console.WriteLine();
    Console.WriteLine($"Researching \"{topic}\"…");
    Console.WriteLine();

    var response = await chatClient.GetResponseAsync(messages, chatOptions);

    // Append the full response (including tool-call history) to the conversation.
    messages.AddRange(response.Messages);

    Console.WriteLine("───────────────────────────────────────");
    Console.WriteLine(response.Text);
    Console.WriteLine("───────────────────────────────────────");

    Console.WriteLine();
    Console.Write("Enter another topic (or 'quit' to exit): ");
    topic = Console.ReadLine();
}

Console.WriteLine("Goodbye!");

