using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------

/// <summary>Tools the research agent can invoke during its loop.</summary>
static class ResearchTools
{
    private static readonly HttpClient s_http = new();
    private static readonly List<string> s_notes = [];

    [Description("Search the web for a query and return a summary of the top results. Use this to discover facts about a topic.")]
    public static async Task<string> WebSearch(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍  Searching: {query}");

        // Use Wikipedia's public search API (no key required).
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://en.wikipedia.org/w/api.php?action=opensearch&search={encoded}&limit=5&format=json";

        try
        {
            var json = await s_http.GetStringAsync(url);
            // OpenSearch returns: [ query, [titles], [descriptions], [urls] ]
            var doc = System.Text.Json.JsonDocument.Parse(json);
            var titles = doc.RootElement[1];
            var descriptions = doc.RootElement[2];
            var urls = doc.RootElement[3];

            if (titles.GetArrayLength() == 0)
                return "No results found.";

            var sb = new System.Text.StringBuilder();
            for (int i = 0; i < titles.GetArrayLength(); i++)
            {
                sb.AppendLine($"- **{titles[i].GetString()}**: {descriptions[i].GetString()}");
                sb.AppendLine($"  {urls[i].GetString()}");
            }
            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note. Use this to record important facts or findings you want to include in the final summary.")]
    public static string SaveNote(
        [Description("The note text to save")] string note)
    {
        s_notes.Add(note);
        Console.WriteLine($"  📝  Note saved ({s_notes.Count} total)");
        return $"Note saved. You now have {s_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes so far.")]
    public static string GetNotes()
    {
        if (s_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new System.Text.StringBuilder();
        for (int i = 0; i < s_notes.Count; i++)
            sb.AppendLine($"{i + 1}. {s_notes[i]}");
        return sb.ToString();
    }
}

// ---------------------------------------------------------------------------
// Agent loop
// ---------------------------------------------------------------------------

